--
-- Create or alter procedure [SCore].[SCHEMABINDING]
--
GO
CREATE OR ALTER PROCEDURE [SCore].[SCHEMABINDING]
	(@Apply BIT = 1)
AS
BEGIN
	SET NOCOUNT ON;

	DECLARE @ID			   INT,
			@DefinitionSQL NVARCHAR(MAX),
			@CurrentString NVARCHAR(25),
			@NewString	   NVARCHAR(25),
			@TryCount	   INT = 0,
			@MaxTrys	   INT = 20;

	DECLARE @ErrorList TABLE
		(
			ErrorNumber NVARCHAR(50),
			ErrorSeverity NVARCHAR(50),
			ErrorState NVARCHAR(50),
			ErrorProcedure NVARCHAR(MAX),
			ErrorLine NVARCHAR(MAX),
			ErrorMessage NVARCHAR(MAX)
		);

	IF @Apply = 1
	BEGIN
		SET @CurrentString = N'--WITH SCHEMABINDING';
		SET @NewString = N' WITH SCHEMABINDING';
	END;
	ELSE
	BEGIN
		SET @NewString = N'--WITH SCHEMABINDING';
		SET @CurrentString = N'WITH SCHEMABINDING';
	END;

	DECLARE @MaxID	   INT,
			@CurrentID INT;

	DECLARE @ObjectDefinitions TABLE
		(
			ID INT NOT NULL IDENTITY(1, 1) PRIMARY KEY,
			ObjectDefinition NVARCHAR(MAX) NOT NULL DEFAULT('')
		);

	WHILE EXISTS
			   (
				   SELECT	1
				   FROM		sys.objects o
				   WHERE	(OBJECT_DEFINITION(o.object_id) LIKE N'%' + @CurrentString + N'%')
						AND (OBJECT_DEFINITION(o.object_id)NOT LIKE N'%' + @NewString + N'%')
						AND (NOT EXISTS
					   (
						   SELECT	1
						   FROM		sys.computed_columns cc
						   WHERE	cc.definition LIKE N'%' + o.name + N'%'
					   )
							)
			   )
	BEGIN
		SET @TryCount = @TryCount + 1;
		IF(@TryCount > @MaxTrys)
		BEGIN
			SELECT	*
			FROM	@ErrorList;
			THROW 60000, N'Failed Schemabinding', 1;
		END;

		DELETE	FROM @ObjectDefinitions;

		INSERT	@ObjectDefinitions
			(
				ObjectDefinition
			)
		SELECT		OBJECT_DEFINITION(o.object_id)
		FROM		sys.objects o
		WHERE		(OBJECT_DEFINITION(o.object_id) LIKE N'%' + @CurrentString + N'%')
				AND (OBJECT_DEFINITION(o.object_id)NOT LIKE N'%' + @NewString + N'%')
				AND (NOT EXISTS
			(
				SELECT	1
				FROM	sys.computed_columns cc
				WHERE	cc.definition LIKE N'%' + o.name + N'%'
			)
					)
		ORDER BY	NEWID();

		SELECT	@MaxID = MAX(ID),
				@CurrentID = -1
		FROM	@ObjectDefinitions;

		WHILE @CurrentID < @MaxID
		BEGIN
			SELECT		TOP(1)	@DefinitionSQL = ObjectDefinition,
								@CurrentID = ID
			FROM		@ObjectDefinitions
			WHERE		(ID > @CurrentID)
			ORDER BY	ID;

			SET @DefinitionSQL = REPLACE(
											REPLACE(REPLACE(@DefinitionSQL, @CurrentString, @NewString), '----WITH SCHEMABINDING', '--WITH SCHEMABINDING'),
											'CREATE ', 'ALTER '
										);

			BEGIN TRY
				--PRINT @DefinitionSQL;
				EXEC sp_executesql @DefinitionSQL;
			END TRY
			BEGIN CATCH
				INSERT	@ErrorList
					(
						ErrorNumber, ErrorSeverity, ErrorState, ErrorProcedure, ErrorLine, ErrorMessage
					)
				SELECT	ERROR_NUMBER(),
						ERROR_SEVERITY(),
						ERROR_STATE(),
						ERROR_PROCEDURE(),
						ERROR_LINE(),
						ERROR_MESSAGE();
			END CATCH;

			SET @DefinitionSQL = NULL;
		END;
	END;
END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

